import React, { useState, useEffect } from 'react';
import {
  Paper, Typography, TextField, Button, Box, Alert, Select, MenuItem,
  FormControl, InputLabel, Chip, Dialog, DialogTitle, DialogContent,
  DialogActions, List, ListItem, ListItemText, Checkbox
} from '@mui/material';
import axios from 'axios';

function CourseManagement() {
  const [courses, setCourses] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [instructors, setInstructors] = useState([]);
  const [students, setStudents] = useState([]);
  const [formData, setFormData] = useState({
    code: '',
    name: '',
    credits: '',
    description: '',
    semester: '',
    departmentId: '',
    instructorId: ''
  });
  const [message, setMessage] = useState('');
  const [enrollDialogOpen, setEnrollDialogOpen] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [selectedStudents, setSelectedStudents] = useState([]);

  useEffect(() => {
    loadCourses();
    loadDepartments();
    loadInstructors();
    loadStudents();
  }, []);

  const loadCourses = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/courses');
      const courseObjects = response.data.filter(item => typeof item === 'object' && item !== null);
      setCourses(courseObjects);
    } catch (error) {
      console.error('Error loading courses:', error);
    }
  };

  const loadDepartments = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/departments');
      setDepartments(response.data);
    } catch (error) {
      console.error('Error loading departments:', error);
    }
  };

  const loadInstructors = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/instructors');
      setInstructors(response.data);
    } catch (error) {
      console.error('Error loading instructors:', error);
    }
  };

  const loadStudents = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/students');
      setStudents(response.data);
    } catch (error) {
      console.error('Error loading students:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const payload = {
        code: formData.code,
        name: formData.name,
        credits: parseInt(formData.credits),
        description: formData.description,
        semester: formData.semester,
        department: { id: formData.departmentId },
        instructor: { id: formData.instructorId }
      };
      await axios.post('http://localhost:8080/api/courses', payload);
      setMessage('–ö—É—Ä—Å —Å—ä–∑–¥–∞–¥–µ–Ω —É—Å–ø–µ—à–Ω–æ!');
      setFormData({
        code: '',
        name: '',
        credits: '',
        description: '',
        semester: '',
        departmentId: '',
        instructorId: ''
      });
      loadCourses();
      setTimeout(() => setMessage(''), 3000);
    } catch (error) {
      setMessage('–ì—Ä–µ—à–∫–∞ –ø—Ä–∏ —Å—ä–∑–¥–∞–≤–∞–Ω–µ –Ω–∞ –∫—É—Ä—Å');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('–°–∏–≥—É—Ä–Ω–∏ –ª–∏ —Å—Ç–µ?')) {
      try {
        await axios.delete(`http://localhost:8080/api/courses/${id}`);
        setMessage('–ö—É—Ä—Å –∏–∑—Ç—Ä–∏—Ç!');
        loadCourses();
        setTimeout(() => setMessage(''), 3000);
      } catch (error) {
        setMessage('–ì—Ä–µ—à–∫–∞ –ø—Ä–∏ –∏–∑—Ç—Ä–∏–≤–∞–Ω–µ');
      }
    }
  };

  const openEnrollDialog = (course) => {
    setSelectedCourse(course);
    setSelectedStudents(course.students?.map(s => s.id) || []);
    setEnrollDialogOpen(true);
  };

  const handleEnrollToggle = (studentId) => {
    setSelectedStudents(prev => {
      if (prev.includes(studentId)) {
        return prev.filter(id => id !== studentId);
      } else {
        return [...prev, studentId];
      }
    });
  };

  const handleEnrollSave = async () => {
    try {
      await axios.post(`http://localhost:8080/api/courses/${selectedCourse.id}/enroll`, {
        studentIds: selectedStudents
      });
      setMessage('–°—Ç—É–¥–µ–Ω—Ç–∏ –∑–∞–ø–∏—Å–∞–Ω–∏ —É—Å–ø–µ—à–Ω–æ!');
      setEnrollDialogOpen(false);
      loadCourses();
      setTimeout(() => setMessage(''), 3000);
    } catch (error) {
      setMessage('–ì—Ä–µ—à–∫–∞ –ø—Ä–∏ –∑–∞–ø–∏—Å–≤–∞–Ω–µ –Ω–∞ —Å—Ç—É–¥–µ–Ω—Ç–∏');
    }
  };

  return (
    <Box>
      <Paper sx={{ p: 3, mb: 3 }}>
        <Typography variant="h6" gutterBottom>–°—ä–∑–¥–∞–π –Ω–æ–≤ –∫—É—Ä—Å</Typography>
        {message && <Alert severity={message.includes('–ì—Ä–µ—à–∫–∞') ? 'error' : 'success'} sx={{ mb: 2 }}>{message}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="–ö–æ–¥ –Ω–∞ –∫—É—Ä—Å"
            value={formData.code}
            onChange={(e) => setFormData({ ...formData, code: e.target.value })}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="–ò–º–µ –Ω–∞ –∫—É—Ä—Å"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="–ö—Ä–µ–¥–∏—Ç–∏"
            type="number"
            value={formData.credits}
            onChange={(e) => setFormData({ ...formData, credits: e.target.value })}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="–û–ø–∏—Å–∞–Ω–∏–µ"
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
            margin="normal"
            multiline
            rows={2}
          />
          <TextField
            fullWidth
            label="–°–µ–º–µ—Å—Ç—ä—Ä"
            value={formData.semester}
            onChange={(e) => setFormData({ ...formData, semester: e.target.value })}
            margin="normal"
            required
          />
          <FormControl fullWidth margin="normal" required>
            <InputLabel>–ö–∞—Ç–µ–¥—Ä–∞</InputLabel>
            <Select
              value={formData.departmentId}
              onChange={(e) => setFormData({ ...formData, departmentId: e.target.value })}
              label="–ö–∞—Ç–µ–¥—Ä–∞"
            >
              {departments.map((department) => (
                <MenuItem key={department.id} value={department.id}>{department.name}</MenuItem>
              ))}
            </Select>
          </FormControl>
          <FormControl fullWidth margin="normal" required>
            <InputLabel>–ü—Ä–µ–ø–æ–¥–∞–≤–∞—Ç–µ–ª</InputLabel>
            <Select
              value={formData.instructorId}
              onChange={(e) => setFormData({ ...formData, instructorId: e.target.value })}
              label="–ü—Ä–µ–ø–æ–¥–∞–≤–∞—Ç–µ–ª"
            >
              {instructors.map((instructor) => (
                <MenuItem key={instructor.id} value={instructor.id}>
                  {instructor.user?.firstName} {instructor.user?.lastName}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
          <Button type="submit" variant="contained" sx={{ mt: 2 }}>
            –°—ä–∑–¥–∞–π –∫—É—Ä—Å
          </Button>
        </Box>
      </Paper>

      <Paper sx={{ p: 3 }}>
        <Typography variant="h6" gutterBottom>–°–ø–∏—Å—ä–∫ —Å –∫—É—Ä—Å–æ–≤–µ</Typography>
        {courses.map((course) => (
          <Paper key={course.id} sx={{ p: 2, mb: 2, bgcolor: '#f5f5f5' }}>
            <Typography variant="subtitle1">
              <strong>{course.code} - {course.name}</strong>
            </Typography>
            <Typography variant="body2">{course.description}</Typography>
            <Typography variant="body2">–ö—Ä–µ–¥–∏—Ç–∏: {course.credits}</Typography>
            <Typography variant="body2">–°–µ–º–µ—Å—Ç—ä—Ä: {course.semester}</Typography>
            <Typography variant="body2">
              –ü—Ä–µ–ø–æ–¥–∞–≤–∞—Ç–µ–ª: {course.instructor?.user?.firstName} {course.instructor?.user?.lastName}
            </Typography>
            <Typography variant="body2">–ö–∞—Ç–µ–¥—Ä–∞: {course.department?.name}</Typography>
            {course.students && course.students.length > 0 && (
              <Box sx={{ mt: 1 }}>
                <Typography variant="caption">–ó–∞–ø–∏—Å–∞–Ω–∏ —Å—Ç—É–¥–µ–Ω—Ç–∏:</Typography>
                <Box>
                  {course.students.map((student) => (
                    <Chip
                      key={student.id}
                      label={`${student.user?.firstName} ${student.user?.lastName}`}
                      size="small"
                      sx={{ mr: 0.5, mb: 0.5 }}
                    />
                  ))}
                </Box>
              </Box>
            )}
            <Box sx={{ mt: 1 }}>
              <Button
                size="small"
                variant="outlined"
                onClick={() => openEnrollDialog(course)}
                sx={{ mr: 1 }}
              >
                –ó–∞–ø–∏—à–∏ —Å—Ç—É–¥–µ–Ω—Ç–∏
              </Button>
              <Button
                size="small"
                color="error"
                onClick={() => handleDelete(course.id)}
              >
                –ò–∑—Ç—Ä–∏–π
              </Button>
            </Box>
          </Paper>
        ))}
      </Paper>

      <Dialog open={enrollDialogOpen} onClose={() => setEnrollDialogOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>–ó–∞–ø–∏—à–∏ —Å—Ç—É–¥–µ–Ω—Ç–∏ –≤ {selectedCourse?.name}</DialogTitle>
        <DialogContent>
          <List>
            {students.map((student) => (
              <ListItem key={student.id} dense button onClick={() => handleEnrollToggle(student.id)}>
                <Checkbox
                  checked={selectedStudents.includes(student.id)}
                  tabIndex={-1}
                  disableRipple
                />
                <ListItemText
                  primary={`${student.user?.firstName} ${student.user?.lastName}`}
                  secondary={`${student.studentNumber} - ${student.major}`}
                />
              </ListItem>
            ))}
          </List>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setEnrollDialogOpen(false)}>–û—Ç–∫–∞–∂–∏</Button>
          <Button onClick={handleEnrollSave} variant="contained">–ó–∞–ø–∞–∑–∏</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

export default CourseManagement;
